import React from "react";

const contenedorImagenes = ({ alto, imagenes }) => {
  return (
    <div
      className="w-full flex justify-between items-center px-4 gap-4"
      style={{ height: alto }}
    >
      {imagenes.map((item, index) => (
        <div key={index} className="relative flex-1 h-full overflow-hidden rounded-xl shadow-lg">
          {/* Título encima de la imagen */}
          <div className="absolute top-0 left-0 w-full bg-black bg-opacity-50 text-white text-center text-xs sm:text-sm md:text-base lg:text-lg font-semibold p-2 z-10">
            {item.titulo}
          </div>

          {/* Imagen con corte centrado */}
          <img
            src={item.ruta}
            alt={item.titulo}
            className="w-full h-full object-cover"
          />
        </div>
      ))}
    </div>
  );
};

export default contenedorImagenes;
